/**
 * MedX animations theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Keyframes for toast, modal, and skeleton loaders.
 */
const ANIMATIONS_TOKENS = Object.freeze({
  primary: { value: "theme-animations-primary", scope: "theme" },
  secondary: { value: "theme-animations-secondary", scope: "theme" },
  muted: { value: "theme-animations-muted", scope: "theme" },
  accent: { value: "theme-animations-accent", scope: "theme" },
  surface: { value: "theme-animations-surface", scope: "theme" },
});

const ANIMATIONS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ANIMATIONS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const animationsRegistry = new Map();
const ANIMATIONS_listeners = new Set();
let ANIMATIONS_seq = 0;

function createAnimationsId(prefix = "medx-theme-animations") {
  ANIMATIONS_seq += 1;
  return `${prefix}-${ANIMATIONS_seq}`;
}

function registerAnimations(config = {}) {
  const entryId = config.id ?? createAnimationsId();
  const preset = ANIMATIONS_PRESETS[config.preset ?? "default"] ?? ANIMATIONS_PRESETS.default;
  const token = ANIMATIONS_TOKENS[config.token ?? preset.token] ?? ANIMATIONS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ANIMATIONS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  animationsRegistry.set(entryId, entry);
  notifyAnimationsListeners("register", entry);
  return entry;
}

function updateAnimations(id, patch = {}) {
  const entry = animationsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyAnimationsListeners("update", entry);
  return entry;
}

function resolveAnimations(id) {
  const entry = animationsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listAnimationsEntries(filter = {}) {
  let items = Array.from(animationsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onAnimationsEvent(listener) {
  ANIMATIONS_listeners.add(listener);
  return () => ANIMATIONS_listeners.delete(listener);
}

function notifyAnimationsListeners(type, entry) {
  for (const listener of ANIMATIONS_listeners) {
    try {
      listener({ type, entry, registrySize: animationsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:animations] listener error", err.message);
    }
  }
}

function getAnimationsMetrics() {
  const items = listAnimationsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ANIMATIONS_TOKENS).length,
    presets: Object.keys(ANIMATIONS_PRESETS).length,
  };
}

async function runMedxAnimations() {
  console.log("[medx:ui:theme:animations] runtime initialized");
  console.log(`[medx:ui:theme:animations] tokens=${Object.keys(ANIMATIONS_TOKENS).length} presets=${Object.keys(ANIMATIONS_PRESETS).length}`);

  const events = [];
  onAnimationsEvent((e) => events.push(e.type));

  const domains = Object.keys(ANIMATIONS_SUPPLY_CHAIN);
  const presets = Object.keys(ANIMATIONS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerAnimations({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/animations" },
    });
  }

  const first = listAnimationsEntries()[0];
  if (first) updateAnimations(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getAnimationsMetrics();
  const resolved = first ? resolveAnimations(first.id) : null;

  console.log(`[medx:ui:theme:animations] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:animations] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:animations] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:animations] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:animations] bootstrap complete");
}

module.exports = runMedxAnimations;
